<template><ContentWrap :title="t('oa.workRequest.title')"><el-button type="primary" @click="visible=true">{{ t('oa.workRequest.create') }}</el-button><el-table class="mt-12px" :data="list"><el-table-column prop="title" :label="t('oa.workRequest.titleLabel')" /><el-table-column prop="content" :label="t('oa.workRequest.content')" /><el-table-column prop="status" :label="t('oa.workRequest.status')" /></el-table><el-dialog v-model="visible" :title="t('oa.workRequest.create')"><el-form :model="form"><el-form-item :label="t('oa.workRequest.titleLabel')"><el-input v-model="form.title" /></el-form-item><el-form-item :label="t('oa.workRequest.content')"><el-input v-model="form.content" type="textarea" /></el-form-item><el-form-item :label="t('oa.workRequest.urgency')"><el-input-number v-model="form.urgency" :min="1" :max="3" /></el-form-item></el-form><template #footer><el-button @click="visible=false">{{ t('common.cancel') }}</el-button><el-button type="primary" @click="save">{{ t('common.confirm') }}</el-button></template></el-dialog></ContentWrap></template>
<script setup lang="ts">import * as Api from '@/api/bpm/oaWorkRequest'; defineOptions({name:'OaWorkRequest'}); const {t}=useI18n('bpm'); const message=useMessage(); const visible=ref(false); const list=ref<Api.WorkRequestVO[]>([]); const form=reactive<Api.WorkRequestVO>({title:'',content:'',urgency:1}); const load=async()=>{list.value=await Api.getList()}; const save=async()=>{await Api.create(form); visible.value=false; message.success(t('common.saveSuccess')); await load()}; onMounted(load)</script>
